```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Get the actual readable size
    size_t readable = storage.readable();

    // Don't try to preview more than what's available
    size_t actual_preview = std::min(bytes_to_preview, readable);

    // Create a vector to hold the previewed data
    std::vector<uint8_t> result(actual_preview);

    // Peek the data without consuming (doesn't advance read pointer)
    if (actual_preview > 0) {
        storage.peek(result.data(), actual_preview);
    }

    return result;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;

    // Get the number of bytes available to read
    status.readable_size = storage.readable();

    // Get the number of bytes available to write (free space)
    status.free_space = storage.writable();

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Reset both read and write offsets
    storage.reset();
}
```

