# Complete Implementation

```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Convert to unsigned to handle bit operations properly
    using UnsignedT = typename std::make_unsigned<T>::type;
    UnsignedT uvalue = static_cast<UnsignedT>(value);

    // Encode using varint format: 7 bits per byte, MSB as continuation bit
    do {
        uint8_t byte = static_cast<uint8_t>(uvalue & 0x7F); // Extract lower 7 bits
        uvalue >>= 7; // Shift to next 7 bits

        if (uvalue != 0) {
            byte |= 0x80; // Set MSB to indicate more bytes follow
        }

        writer.write(byte);
        bytes_written++;
    } while (uvalue != 0);

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    using UnsignedT = typename std::make_unsigned<T>::type;
    UnsignedT result = 0;
    int shift = 0;

    // Decode varint format: read bytes until MSB is 0
    while (true) {
        uint8_t byte;
        reader.read(byte);

        // Extract lower 7 bits and add to result at appropriate position
        result |= static_cast<UnsignedT>(byte & 0x7F) << shift;

        // Check if this is the last byte (MSB is 0)
        if ((byte & 0x80) == 0) {
            break;
        }

        shift += 7;
    }

    return static_cast<T>(result);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to store encoded data
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Encode the value
    hexi::pmc::binary_stream_writer writer(adaptor);
    encode_varint(writer, original_value);

    // Decode the value
    hexi::pmc::binary_stream_reader reader(adaptor);
    T decoded_value = decode_varint<T>(reader);

    // Verify roundtrip correctness
    return decoded_value == original_value;
}
```

## Explanation:

**`encode_varint`:**
- Converts the value to unsigned to safely perform bit operations
- Extracts 7 bits at a time from the value
- Sets the MSB (most significant bit) to 1 if more bytes are needed, 0 for the last byte
- Writes each byte to the stream and counts bytes written

**`decode_varint`:**
- Reads bytes one at a time from the stream
- Extracts the lower 7 bits from each byte
- Combines them into the result value with appropriate bit shifting
- Stops when a byte with MSB = 0 is encountered (last byte)

**`encode_decode_roundtrip`:**
- Creates a buffer and adaptor for binary stream operations
- Encodes the original value using `encode_varint`
- Decodes it back using `decode_varint`
- Returns `true` if the decoded value matches the original, verifying correctness

